#include <bits/stdc++.h>
using namespace std;
int main()
{
    string a;
    int b=0;
    cin>>a;
    if (a.length()<5) cout<<b;
    else {
        for(int i=0;i<a.length()-4;i++)
        {
            if((a[i]=='l')&&(a[i+1]=='u')&&(a[i+2]=='o')&&(a[i+3]=='g')&&(a[i+4]=='u'))
            {
                b++;
                i=i+4;
            }
        }
    cout<<b;
    }
    return 0;
}
